public static unsafe Blob FromStream(Stream stream)
{
    using var ms = new MemoryStream();
    stream.CopyTo(ms);
    var length = (int)ms.Length;
    var dataPtr = Marshal.AllocCoTaskMem(length);
    Marshal.Copy(ms.GetBuffer(), 0, dataPtr, length);
    return new Blob(dataPtr, length, MemoryMode.ReadOnly, () => Marshal.FreeCoTaskMem(dataPtr));
}

public static unsafe Blob FromStream(Stream stream)
{
    using var ms = new MemoryStream();
    stream.CopyTo(ms);
    var data = ms.ToArray();
    var handle = GCHandle.Alloc(data, GCHandleType.Pinned);
    var dataPtr = handle.AddrOfPinnedObject();
    return new Blob(dataPtr, data.Length, MemoryMode.ReadOnly, () => handle.Free());
}
